import React, { useState, useEffect  } from "react";
import { Link } from "react-router-dom";
import CatalogueCard from "../components/CatalogueCard";

function EmpDashboard({ setModuleName }) {
   const [username, setUsername] = useState("");
   const [role, setRole] = useState("");
   const [office, setOffice] = useState("");
   const [empname, setEmpName] = useState("");
   const userData = localStorage.getItem("user");
   const cards = [
    { link: "/master/office",   title: "Office Management",  subtitle: "",   bgColor: "#eff6ff", iconColor: "#1d4ed8", icon: "fa fa-building" },
    { link: "/master/employee",    title: "Employee Management",    subtitle: "",    bgColor: "#f0fdf4", iconColor: "#15803d", icon: "fa fa-user"    },
    { link: "/master/usermanagement",    title: "User Management",    subtitle: "",    bgColor: "#fffbeb", iconColor: "#d97706", icon: "fa fa-users"    },
    { link: "/master/schememasterentry",    title: "Scheme Master Entry",    subtitle: "",    bgColor: "#fef2f2", iconColor: "#dc2626", icon: "fa fa-list-alt"    },

  ];

   useEffect(() => {
      setModuleName("Employee Dashboard");
      const userData = JSON.parse(localStorage.getItem("user") || "{}");
      setUsername(userData.user_id); // or user.name if your API returns "name"
      setRole(userData.role);
      setOffice(userData.office);
      setEmpName(userData.empname);
    //   if (userData) { 
    //   const user = JSON.parse(userData);
    //   //console.log("User data from localStorage:", user);

    // }
      console.log(console.log("Emp data from localStorage:", userData));
   }, []);

  return (  

      <div className="container-fluid content-inner mt-n5 px-3 py-0">
          <div className="row g-3 py-3">
              <div className="col-xl-3 col-lg-4">
                <div className="card" style={{minHeight:"200px"}}>
                    <div className="card-body">
                      <img src="./assets/images/user2.png" alt="Profile" className="img-fluid rounded-circle mb-3" 
                      style={{ width: "50px", height: "50px" }} />
                      <br />
                      <label className="form-label col-form-label col-form-label-sm"><i class="fa fa-user"></i> <strong>{empname}</strong><br/>
                      <i class="fa fa-envelope"></i> <strong>{username}</strong><br/>
                      <i class="fa fa-id-badge"></i> <strong>{role}</strong><br/>
                      <i class="fa fa-building"></i> <strong>{office}</strong> </label>
                    </div>
                </div>
                <div className="card mt-2" style={{minHeight:"200px"}}>
                    <div className="card-header d-flex justify-content-between border-0">
                      <div className="header-title">Quick Links</div>
                    </div>
                    <div className="card-body">
                      <div className="row g-3 px-3">
                        {cards.map((card, index) => (
                          <CatalogueCard key={index} {...card} />
                        ))}
                      </div>
                    </div>
                </div>
                <div className="card mt-2" style={{minHeight:"200px"}}>
                    <div className="card-header d-flex justify-content-between border-0">
                      <div className="header-title">Download Forms</div>
                    </div>
                    <div className="card-body">
                    </div>
                </div>
                <div className="card mt-2" style={{minHeight:"200px"}}>
                    <div className="card-header d-flex justify-content-between border-0">
                      <div className="header-title">Helpdesk</div>
                    </div>
                    <div className="card-body">
                    </div>
                </div>
            </div>
            <div className="col-xl-6 col-lg-4">
                <div className="card" style={{minHeight:"200px"}}>
                    <div className="card-header d-flex justify-content-between border-0">
                      <div className="header-title"></div>
                    </div>
                    <div className="card-body">
                    </div>
                </div>
            </div>
            <div className="col-xl-3 col-lg-4">
                <div className="card" style={{minHeight:"200px"}}>
                    <div className="card-header d-flex justify-content-between border-0">
                      <div className="header-title">Search employee</div>
                    </div>
                    <div className="card-body">
                    </div>
                </div>
                <div className="card mt-2" style={{minHeight:"200px"}}>
                    <div className="card-header d-flex justify-content-between border-0">
                      <div className="header-title">Leave Register</div>
                    </div>
                    <div className="card-body">
                    </div>
                </div>
                <div className="card mt-2" style={{minHeight:"200px"}}>
                    <div className="card-header d-flex justify-content-between border-0">
                      <div className="header-title">Pending Approvals</div>
                    </div>
                    <div className="card-body">
                    </div>
                </div>
                <div className="card mt-2" style={{minHeight:"200px"}}>
                    <div className="card-header d-flex justify-content-between border-0">
                      <div className="header-title">Pending Processings</div>
                    </div>
                    <div className="card-body">
                    </div>
                </div>
            </div>
          </div>    
      </div>
  );
}

export default EmpDashboard;
